# TAB 1 — LINKS DIRECTORY
# ═══════════════════════════════════════════════════════════════════════════════
def tab_links(links):
    st.markdown('<div class="sh">🔗 Sarcoma Resource Directory</div>', unsafe_allow_html=True)
    st.markdown("A hand-curated collection of the most trusted and useful resources for sarcoma patients, caregivers, and researchers.")

    # Filters
    col1, col2, col3 = st.columns([2, 2, 2])
    with col1:
        search = st.text_input("🔍 Search resources", placeholder="e.g. clinical trials, GIST, support…")
    with col2:
        cat_f = st.selectbox("Category", LINK_CATS)
    with col3:
        type_f = st.selectbox("Sarcoma Type", ["All Types"] + ALL_TYPES[1:])

    # Filter
    filtered = links
    if search:
        s = search.lower()
        filtered = [l for l in filtered if s in l["name"].lower() or s in l["description"].lower() or s in l["category"].lower()]
    if cat_f != "All Categories":
        filtered = [l for l in filtered if l["category"] == cat_f]
    if type_f != "All Types":
        filtered = [l for l in filtered if type_f in l.get("sarcoma_types", ["All Types"]) or "All Types" in l.get("sarcoma_types", [])]

    st.markdown(f"**{len(filtered)} resources found**")

    # Render — batch all cards into ONE st.markdown() call per group to avoid
    # Streamlit dropping unsafe_allow_html on repeated calls within a loop.
    if cat_f == "All Categories":
        cats = sorted(set(l["category"] for l in filtered))
        for cat in cats:
            cat_links = [l for l in filtered if l["category"] == cat]
            if not cat_links:
                continue
            st.markdown(f'<div class="sh">{cat} &nbsp;({len(cat_links)})</div>', unsafe_allow_html=True)
            st.markdown(_build_cards_html(cat_links), unsafe_allow_html=True)
    else:
        if filtered:
            st.markdown(_build_cards_html(filtered), unsafe_allow_html=True)

    if not filtered:
        st.info("No resources match your search. Try a different term or clear the filters.")

    # Add new link
    with st.expander("➕ Suggest a New Resource"):
        with st.form("add_link_form"):
            c1, c2 = st.columns(2)
            with c1:
                n = st.text_input("Resource Name *")
                u = st.text_input("URL *", placeholder="https://…")
                cat_sel = st.selectbox("Category *", LINK_CATS[1:])
            with c2:
                d = st.text_area("Description *", max_chars=250, height=100)
                t_sel = st.multiselect("Sarcoma Types (leave blank for All)", ALL_TYPES[1:])

            sub = st.form_submit_button("📤 Submit Suggestion")
            if sub:
                if n and u and d:
                    new = {
                        "id": f"l{uuid.uuid4().hex[:6]}",
                        "name": n, "url": u, "description": d, "category": cat_sel,
                        "sarcoma_types": t_sel if t_sel else ["All Types"],
                        "featured": False,
                        "submitted": str(datetime.now().date())
                    }
                    links.append(new)
                    save_json("links.json", links)
                    st.success("✅ Thank you! Resource suggestion saved.")
                    st.rerun()
                else:
                    st.error("Please fill in all required (*) fields.")

    return links


def _build_link_card_html(link):
    """Return HTML string for one link card (no st.markdown call)."""
    featured_html = '<span class="featured-badge">★ Featured</span>' if link.get("featured") else ""
    tags_html = "".join(f'<span class="ltag">{t}</span>' for t in link.get("sarcoma_types", []))
    return (
        f'<div class="lcard">'
        f'{featured_html}'
        f'<h4><a href="{link["url"]}" target="_blank" style="color:{NAVY};text-decoration:none;">🔗 {link["name"]}</a></h4>'
        f'<p>{link["description"]}</p>'
        f'<div style="margin-top:0.4rem;">{tags_html}</div>'
        f'</div>'
    )


def _build_cards_html(link_list):
    """Concatenate card HTML for a list of links into a single block."""
    return "\n".join(_build_link_card_html(lnk) for lnk in link_list)


