# TAB 2 — MY STORY
# ═══════════════════════════════════════════════════════════════════════════════
def tab_my_story():
    st.markdown('<div class="sh">📖 My Sarcoma Story</div>', unsafe_allow_html=True)
    st.markdown("*A personal account of living with sarcoma — written to help others feel less alone on this journey.*")

    col1, col2 = st.columns([3, 2], gap="large")

    with col1:
        story_data = load_json("my_story.json", {
            "author": "Your Name",
            "subtitle": "Sarcoma Survivor",
            "diagnosis": "",
            "treatment": "",
            "challenges": "",
            "hope": "",
            "message": "",
        })

        # Author header
        st.markdown(f"""
        <div class="scard">
            <div class="scard-author">{story_data.get('author', 'Your Name')}</div>
            <div class="scard-meta">{story_data.get('subtitle', 'Sarcoma Survivor')}</div>
            <p><em>Use the edit form below to write and publish your personal sarcoma story. 
            Each section helps readers understand a different chapter of your journey.</em></p>
        </div>
        """, unsafe_allow_html=True)

        # Published story display
        sections = [
            ("diagnosis",  "🔍", "The Diagnosis"),
            ("treatment",  "💊", "Treatment Journey"),
            ("challenges", "🌊", "Challenges Along the Way"),
            ("hope",       "🌟", "What Gives Me Hope"),
            ("message",    "💌", "To Newly Diagnosed Patients"),
        ]
        has_content = any(story_data.get(k) for k, _, _ in sections)

        if has_content:
            st.markdown('<div class="sh">📖 Published Story</div>', unsafe_allow_html=True)
            for key, emoji, label in sections:
                content = story_data.get(key, "").strip()
                if content:
                    st.markdown(f"**{emoji} {label}**")
                    st.markdown(content)
                    st.divider()

        # Edit form
        with st.expander("✏️ Edit My Story", expanded=not has_content):
            with st.form("edit_story_form"):
                author   = st.text_input("Your Name", value=story_data.get("author", ""))
                subtitle = st.text_input("Tagline / Role", value=story_data.get("subtitle", ""),
                                         placeholder="e.g. Sarcoma Survivor · Advocate")
                st.divider()
                diagnosis  = st.text_area("🔍 The Diagnosis", value=story_data.get("diagnosis", ""), height=130,
                                           placeholder="When and how were you diagnosed? How did it feel?")
                treatment  = st.text_area("💊 Treatment Journey", value=story_data.get("treatment", ""), height=130,
                                           placeholder="What treatments did you receive? Where were you treated?")
                challenges = st.text_area("🌊 Challenges Along the Way", value=story_data.get("challenges", ""), height=110,
                                           placeholder="What were the hardest parts — physically, emotionally, practically?")
                hope       = st.text_area("🌟 What Gives Me Hope", value=story_data.get("hope", ""), height=110,
                                           placeholder="What has helped you most? What keeps you going?")
                message    = st.text_area("💌 Message to Newly Diagnosed Patients", value=story_data.get("message", ""), height=110,
                                           placeholder="What would you say to someone just starting this journey?")

                if st.form_submit_button("💾 Save & Publish Story"):
                    save_json("my_story.json", {
                        "author": author, "subtitle": subtitle,
                        "diagnosis": diagnosis, "treatment": treatment,
                        "challenges": challenges, "hope": hope, "message": message,
                        "updated": str(datetime.now())
                    })
                    st.success("✅ Story saved and published!")
                    st.rerun()

    with col2:
        st.markdown('<div class="sh">📅 My Journey Timeline</div>', unsafe_allow_html=True)

        milestones = load_json("milestones.json", [])

        for m in milestones:
            st.markdown(f"""
            <div class="milestone">
                <div class="milestone-date">{m.get('date','')}</div>
                <div class="milestone-title">{m.get('title','')}</div>
                <div class="milestone-note">{m.get('note','')}</div>
            </div>
            """, unsafe_allow_html=True)

        if not milestones:
            st.info("Add milestones to build a visual timeline of your journey.")

        with st.expander("➕ Add Timeline Milestone"):
            with st.form("milestone_form"):
                m_date  = st.text_input("Date", placeholder="e.g. March 2022")
                m_title = st.text_input("Milestone", placeholder="e.g. First chemo cycle completed")
                m_note  = st.text_area("Note (optional)", height=60)
                if st.form_submit_button("Add"):
                    if m_date and m_title:
                        milestones.append({"date": m_date, "title": m_title, "note": m_note})
                        save_json("milestones.json", milestones)
                        st.success("Milestone added!")
                        st.rerun()
                    else:
                        st.error("Date and milestone title required.")

        # Photo uploads
        st.markdown('<div class="sh">📸 My Photos</div>', unsafe_allow_html=True)
        photos = load_json("photos.json", [])
        photo_up = st.file_uploader("Upload a photo (optional)", type=["jpg","jpeg","png","webp"], key="my_photo")
        if photo_up:
            cap = st.text_input("Caption")
            if st.button("Save Photo"):
                fid = uuid.uuid4().hex[:8]
                fname = f"{fid}_{photo_up.name}"
                fpath = UPLOAD_DIR / "stories" / fname
                with open(fpath, "wb") as f:
                    f.write(photo_up.getbuffer())
                photos.append({"filename": fname, "caption": cap, "date": str(datetime.now().date())})
                save_json("photos.json", photos)
                st.success("Photo saved!")
                st.rerun()
        for p in reversed(photos[-4:]):
            fpath = UPLOAD_DIR / "stories" / p["filename"]
            if fpath.exists():
                st.image(str(fpath), caption=p.get("caption",""), use_container_width=True)


