# TAB 3 — PATIENT STORIES
# ═══════════════════════════════════════════════════════════════════════════════
def tab_patient_stories(stories):
    st.markdown('<div class="sh">💬 Patient Stories</div>', unsafe_allow_html=True)
    st.markdown("Every sarcoma journey is unique. Share yours to help others feel less alone.")

    with st.expander("📝 Share Your Story", expanded=(len(stories) == 0)):
        with st.form("story_form"):
            c1, c2 = st.columns(2)
            with c1:
                name         = st.text_input("Your Name (or 'Anonymous') *")
                sarcoma_type = st.selectbox("Sarcoma Type *", ALL_TYPES)
                location     = st.text_input("Location (optional)", placeholder="City, Country")
            with c2:
                status = st.selectbox("Status", [
                    "Currently in treatment", "In remission", "Long-term survivor",
                    "Caregiver", "Family member", "Bereaved", "Other"
                ])
                diag_year = st.number_input("Year Diagnosed", min_value=1950,
                                             max_value=datetime.now().year, value=2020, step=1)

            story_text = st.text_area("Your Story *", height=200, placeholder=(
                "Share your diagnosis story, treatment experience, what helped you, "
                "challenges you faced, and any advice for others on this journey…"
            ))
            uploaded = st.file_uploader(
                "Attach supporting files (optional)",
                type=["pdf","png","jpg","jpeg","docx","txt"],
                accept_multiple_files=True,
                help="Photos, documents, or any files that accompany your story"
            )
            consent = st.checkbox("I consent to this story being published on the Sarcoma Hub *")
            sub = st.form_submit_button("📤 Submit My Story")

            if sub:
                if name and sarcoma_type != "All Types" and story_text and consent:
                    saved_files = []
                    for uf in (uploaded or []):
                        fid  = uuid.uuid4().hex[:8]
                        fn   = f"{fid}_{uf.name}"
                        fp   = UPLOAD_DIR / "stories" / fn
                        with open(fp, "wb") as f:
                            f.write(uf.getbuffer())
                        saved_files.append({"filename": fn, "original": uf.name, "type": uf.type})

                    stories.append({
                        "id": uuid.uuid4().hex[:8],
                        "name": name, "sarcoma_type": sarcoma_type,
                        "location": location, "status": status,
                        "diagnosis_year": int(diag_year),
                        "story": story_text, "files": saved_files,
                        "submitted": str(datetime.now()),
                        "date": str(datetime.now().date())
                    })
                    save_json("stories.json", stories)
                    st.success("✅ Thank you for sharing your story. It will help others on this journey.")
                    st.balloons()
                    st.rerun()
                else:
                    if not consent:
                        st.error("Please tick the consent checkbox to submit.")
                    elif sarcoma_type == "All Types":
                        st.error("Please select your specific sarcoma type.")
                    else:
                        st.error("Please fill in all required (*) fields.")

    # Browse stories
    st.markdown(f'<div class="sh">📚 Community Stories ({len(stories)})</div>', unsafe_allow_html=True)

    if not stories:
        st.info("No stories yet — be the first to share yours using the form above!")
    else:
        c1, c2 = st.columns(2)
        with c1:
            type_f2 = st.selectbox("Filter by type", ["All Types"] + ALL_TYPES[1:], key="stype_f")
        with c2:
            status_f = st.selectbox("Filter by status", ["All", "Currently in treatment",
                "In remission", "Long-term survivor", "Caregiver", "Family member", "Other"])

        disp = [s for s in stories
                if (type_f2 == "All Types" or s.get("sarcoma_type") == type_f2)
                and (status_f == "All" or s.get("status") == status_f)]

        if not disp:
            st.info("No stories match these filters.")

        for s in reversed(disp):
            files_html = ""
            for fi in s.get("files", []):
                files_html += f'<span class="ltag">📎 {fi["original"]}</span>'
            loc_str = f' · {s["location"]}' if s.get("location") else ""
            s_col, d_col = st.columns([11, 1])
            with s_col:
                st.markdown(f"""
            <div class="scard">
                <div class="scard-author">👤 {s.get('name','Anonymous')}</div>
                <div class="scard-meta">
                    {s.get('sarcoma_type','')} · {s.get('status','')}
                    · Diagnosed {s.get('diagnosis_year','')}{loc_str} · {s.get('date','')}
                </div>
                <p>{s.get('story','')}</p>
                {('<div style="margin-top:0.5rem;">' + files_html + '</div>') if files_html else ''}
            </div>
            """, unsafe_allow_html=True)
            with d_col:
                if st.button("🗑", key=f"del_story_{s['id']}",
                             help="Delete this story",
                             use_container_width=True):
                    stories = [x for x in stories if x["id"] != s["id"]]
                    save_json("stories.json", stories)
                    st.rerun()

            # Show downloadable attachments
            for fi in s.get("files", []):
                fpath = UPLOAD_DIR / "stories" / fi["filename"]
                if fpath.exists() and fi.get("type","").startswith("image"):
                    st.image(str(fpath), caption=fi["original"], width=250)
                elif fpath.exists():
                    with open(fpath, "rb") as f:
                        st.download_button(f"⬇️ {fi['original']}", f.read(),
                                           file_name=fi["original"], key=f"dl_s_{fi['filename']}")
    return stories


