# TAB 4 — RESOURCE LIBRARY
# ═══════════════════════════════════════════════════════════════════════════════
def tab_resources(resources):
    st.markdown('<div class="sh">📁 Resource Library</div>', unsafe_allow_html=True)
    st.markdown("A shared library of documents, guides, research papers, and patient materials — uploaded by the community.")

    with st.expander("📤 Upload a Resource"):
        with st.form("res_form"):
            c1, c2 = st.columns(2)
            with c1:
                r_name   = st.text_input("Resource Title *")
                r_type   = st.selectbox("Resource Type", RESOURCE_TYPES[1:])
                r_author = st.text_input("Author / Source")
            with c2:
                r_types = st.multiselect("Relevant Sarcoma Types", ALL_TYPES[1:])
                r_desc  = st.text_area("Description", height=80)

            r_file = st.file_uploader("Upload File *", type=["pdf","docx","pptx","xlsx","txt","png","jpg"])
            sub_r  = st.form_submit_button("📤 Upload Resource")

            if sub_r:
                if r_name and r_file:
                    fid  = uuid.uuid4().hex[:8]
                    fn   = f"{fid}_{r_file.name}"
                    fp   = UPLOAD_DIR / "resources" / fn
                    with open(fp, "wb") as f:
                        f.write(r_file.getbuffer())
                    resources.append({
                        "id": fid, "name": r_name, "type": r_type,
                        "author": r_author,
                        "sarcoma_types": r_types if r_types else ["All Types"],
                        "description": r_desc,
                        "filename": fn, "original": r_file.name,
                        "size": r_file.size,
                        "uploaded": str(datetime.now()),
                        "date": str(datetime.now().date())
                    })
                    save_json("resources.json", resources)
                    st.success(f"✅ '{r_name}' uploaded successfully!")
                    st.rerun()
                else:
                    st.error("Please provide a title and select a file.")

    st.markdown(f"**{len(resources)} documents in library**")

    if not resources:
        st.info("No resources yet. Upload the first document to get started!")
    else:
        c1, c2 = st.columns(2)
        with c1:
            search_r = st.text_input("🔍 Search library", key="res_s")
        with c2:
            type_r = st.selectbox("Resource Type", RESOURCE_TYPES, key="res_t")

        disp_r = [r for r in resources
                  if (not search_r or search_r.lower() in r["name"].lower() or search_r.lower() in r.get("description","").lower())
                  and (type_r == "All" or r.get("type") == type_r)]

        for r in reversed(disp_r):
            size_kb = r.get("size", 0) // 1024
            tags_html = "".join(f'<span class="ltag">{t}</span>' for t in r.get("sarcoma_types",[]))
            st.markdown(f"""
            <div class="lcard">
                <h4>📄 {r['name']}</h4>
                <div style="font-size:0.78rem;color:{MUTED};margin-bottom:0.4rem;">
                    {r.get('type','')} · {r.get('author','Unknown') or 'Unknown'} · {r.get('date','')} · {size_kb} KB
                </div>
                <p>{r.get('description','')}</p>
                <div style="margin-top:0.3rem;">{tags_html}</div>
                <div style="margin-top:0.35rem;font-size:0.78rem;color:{TEAL};">📎 {r.get('original','')}</div>
            </div>
            """, unsafe_allow_html=True)
            fp = UPLOAD_DIR / "resources" / r["filename"]
            if fp.exists():
                with open(fp, "rb") as f:
                    st.download_button(f"⬇️ Download {r['original']}", f.read(),
                                       file_name=r["original"], key=f"dl_r_{r['id']}")

    return resources


