# TAB 5 — SARCOMA NAVIGATOR
# ═══════════════════════════════════════════════════════════════════════════════
def tab_navigator():
    st.markdown('<div class="sh">🔬 Sarcoma Type Navigator</div>', unsafe_allow_html=True)
    st.markdown("Sarcoma is not one disease — it is a family of **70+ distinct cancers**. Understanding your specific subtype is essential.")

    c1, c2 = st.columns(2)
    with c1:
        st.info("🦴 **Bone Sarcomas** arise from bone tissue — roughly 30% of all sarcomas.")
    with c2:
        st.info("🩸 **Soft Tissue Sarcomas** arise from muscle, fat, nerves, and vessels — roughly 70%.")

    search_t = st.text_input("🔍 Search sarcoma types", placeholder="e.g. GIST, osteosarcoma, synovial…")

    for group, types in NAVIGATOR.items():
        filtered_t = [t for t in types
                      if not search_t or search_t.lower() in t["name"].lower() or search_t.lower() in t["desc"].lower()]
        if not filtered_t:
            continue

        st.markdown(f'<div class="sh">{group} &nbsp;({len(filtered_t)} types)</div>', unsafe_allow_html=True)

        # 3-column grid
        cols = st.columns(3, gap="medium")
        for i, t in enumerate(filtered_t):
            badge_class = "badge-bone" if t["badge"] == "bone" else "badge-soft"
            badge_label = "Bone" if t["badge"] == "bone" else "Soft Tissue"
            card_class  = "bone" if t["badge"] == "bone" else "soft"
            facts_html  = "".join(f"<li>{f}</li>" for f in t["facts"])

            with cols[i % 3]:
                st.markdown(f"""
                <div class="tcard {card_class}">
                    <span class="{badge_class}">{badge_label}</span>
                    <h3>{t['name']}</h3>
                    <div class="tcard-prev">📊 {t['prev']}</div>
                    <div class="tcard-age">👥 {t['age']}</div>
                    <div class="tcard-desc">{t['desc']}</div>
                    <ul>{facts_html}</ul>
                    <a href="{t['url']}" target="_blank"
                       style="font-size:0.79rem;color:{TEAL};font-weight:700;text-decoration:none;">
                        Learn More →
                    </a>
                </div>
                """, unsafe_allow_html=True)
                st.write("")  # vertical spacer


