# TAB 6 — COMMUNITY FORUM
# ═══════════════════════════════════════════════════════════════════════════════
def tab_forum(forum):
    st.markdown('<div class="sh">💭 Community Forum</div>', unsafe_allow_html=True)
    st.markdown("A supportive space to ask questions, share experiences, and connect with others living with sarcoma.")

    TAG_COLORS = {
        "Question":        "#E8F0FE",
        "My Experience":   "#E6F4F1",
        "Treatment":       "#FFF8E1",
        "Clinical Trials": "#F3E5F5",
        "Emotional Support":"#FCE4EC",
        "Caregivers":      "#E8F5E9",
        "Nutrition":       "#FFF3E0",
        "Second Opinion":  "#E0F2F1",
        "Other":           "#F5F5F5",
    }

    with st.expander("✏️ Start a New Discussion"):
        with st.form("forum_form"):
            c1, c2 = st.columns(2)
            with c1:
                p_name  = st.text_input("Your Name (or 'Anonymous')")
                p_title = st.text_input("Discussion Title *")
                p_tag   = st.selectbox("Topic Tag", FORUM_TAGS)
            with c2:
                p_type  = st.selectbox("Sarcoma Type (optional)", ["Not specified"] + ALL_TYPES[1:])
                p_body  = st.text_area("Your Post *", height=120)

            if st.form_submit_button("📤 Post"):
                if p_title and p_body:
                    forum.append({
                        "id": uuid.uuid4().hex[:8],
                        "name": p_name or "Anonymous",
                        "title": p_title, "tag": p_tag,
                        "sarcoma_type": p_type if p_type != "Not specified" else "",
                        "body": p_body, "replies": [],
                        "posted": str(datetime.now()),
                        "date": str(datetime.now().date())
                    })
                    save_json("forum.json", forum)
                    st.success("✅ Your post has been submitted!")
                    st.rerun()
                else:
                    st.error("Please fill in the title and post body.")

    # Filter & display
    st.markdown(f'<div class="sh">💬 Discussions ({len(forum)})</div>', unsafe_allow_html=True)

    if not forum:
        st.info("No discussions yet. Start the conversation!")
    else:
        c1, c2 = st.columns(2)
        with c1:
            tag_f = st.selectbox("Filter by topic", ["All"] + FORUM_TAGS)
        with c2:
            type_f3 = st.selectbox("Filter by sarcoma type", ["All Types"] + ALL_TYPES[1:], key="forum_type")

        disp_f = [p for p in forum
                  if (tag_f == "All" or p.get("tag") == tag_f)
                  and (type_f3 == "All Types" or p.get("sarcoma_type") == type_f3 or not p.get("sarcoma_type"))]

        if not disp_f:
            st.info("No posts match these filters.")

        for post in reversed(disp_f):
            tc = TAG_COLORS.get(post.get("tag",""), "#F0F4F8")
            type_str = f' · {post["sarcoma_type"]}' if post.get("sarcoma_type") else ""

            st.markdown(f"""
            <div class="fpost">
                <div style="display:flex;justify-content:space-between;align-items:flex-start;">
                    <div class="fpost-title">💬 {post['title']}</div>
                    <span style="background:{tc};border-radius:12px;padding:0.1rem 0.65rem;
                                 font-size:0.7rem;font-weight:700;color:{NAVY};white-space:nowrap;margin-left:0.5rem;">
                        {post.get('tag','')}
                    </span>
                </div>
                <div class="fmeta">👤 {post.get('name','Anonymous')}{type_str} · {post.get('date','')}</div>
                <p>{post.get('body','')}</p>
            </div>
            """, unsafe_allow_html=True)

            # Replies
            for reply in post.get("replies", []):
                st.markdown(f"""
                <div class="freply">
                    <div class="freply-name">↪ {reply.get('name','Anonymous')}</div>
                    <div class="freply-date">{reply.get('date','')}</div>
                    <div style="margin-top:0.3rem;">{reply.get('body','')}</div>
                </div>
                """, unsafe_allow_html=True)

            # Reply form
            n_replies = len(post.get("replies", []))
            with st.expander(f"💬 Reply ({n_replies} {'reply' if n_replies==1 else 'replies'})"):
                with st.form(f"reply_{post['id']}"):
                    r_name = st.text_input("Your Name", key=f"rn_{post['id']}")
                    r_body = st.text_area("Your Reply *", height=80, key=f"rb_{post['id']}")
                    if st.form_submit_button("Submit Reply"):
                        if r_body:
                            reply = {"name": r_name or "Anonymous",
                                     "body": r_body,
                                     "date": str(datetime.now().date())}
                            for p in forum:
                                if p["id"] == post["id"]:
                                    p.setdefault("replies", []).append(reply)
                                    break
                            save_json("forum.json", forum)
                            st.success("Reply submitted!")
                            st.rerun()
                        else:
                            st.error("Please write a reply.")

    return forum



