# TAB 7 — SYMPTOM & SIDE-EFFECT TRACKER
# ═══════════════════════════════════════════════════════════════════════════════

# ── Tracker constants ──────────────────────────────────────────────────────────
CORE_SYMPTOMS = [
    ("pain",      "Pain",           "🩹", "0 = none  →  10 = worst imaginable"),
    ("fatigue",   "Fatigue",        "😴", "0 = full energy  →  10 = unable to get up"),
    ("nausea",    "Nausea",         "🤢", "0 = none  →  10 = constant / vomiting"),
    ("appetite",  "Appetite",       "🍽️", "0 = no appetite  →  10 = normal appetite"),
    ("mood",      "Mood",           "💭", "0 = very low  →  10 = positive"),
    ("sleep",     "Sleep quality",  "🌙", "0 = no sleep  →  10 = well rested"),
    ("mobility",  "Mobility",       "🦿", "0 = bed-bound  →  10 = fully mobile"),
]

ADDITIONAL_SYMPTOMS = [
    "Mouth sores (mucositis)", "Constipation", "Diarrhoea",
    "Shortness of breath", "Swelling / oedema", "Tingling / numbness",
    "Headache", "Fever / chills", "Skin rash / reaction",
    "Hair loss", "Weight loss", "Cognitive fog ('chemo brain')",
    "Anxiety", "Depression / low mood", "Wound / surgical site pain",
]

TREATMENT_PHASES = [
    "Pre-treatment", "Chemotherapy", "Radiation therapy",
    "Surgery recovery", "Targeted therapy", "Immunotherapy",
    "Active surveillance", "Survivorship / Follow-up", "Palliative care",
]

def _tracker_sparkline(vals, color, width=120, height=32):
    """Return a tiny base64 PNG sparkline for a symptom trend."""
    if not MATPLOTLIB_OK or len(vals) < 2:
        return None
    fig, ax = plt.subplots(figsize=(width/72, height/72), dpi=72)
    fig.patch.set_alpha(0)
    ax.set_facecolor('none')
    ax.plot(vals, color=color, linewidth=1.6, solid_capstyle='round')
    ax.fill_between(range(len(vals)), vals, alpha=0.15, color=color)
    ax.set_ylim(0, 10)
    ax.axis('off')
    buf = io.BytesIO()
    fig.savefig(buf, format='png', bbox_inches='tight', pad_inches=0,
                transparent=True, dpi=72)
    plt.close(fig)
    buf.seek(0)
    import base64
    return base64.b64encode(buf.read()).decode()


def _score_color(score, invert=False):
    """Return a CSS color reflecting severity (red=bad, green=good)."""
    if invert:  # higher = better (appetite, mood, sleep, mobility)
        if score >= 7: return "#1B9E8A"   # teal  = good
        if score >= 4: return "#E87B35"   # amber = moderate
        return "#C0392B"                  # red   = poor
    else:        # higher = worse (pain, fatigue, nausea)
        if score <= 3: return "#1B9E8A"
        if score <= 6: return "#E87B35"
        return "#C0392B"


def _generate_pdf_report(entries, patient_name, sarcoma_type, treatment_phase):
    """Generate a printable PDF appointment summary."""
    from reportlab.lib.pagesizes import A4
    from reportlab.lib import colors as rl_colors
    from reportlab.lib.units import mm
    from reportlab.lib.styles import getSampleStyleSheet, ParagraphStyle
    from reportlab.lib.enums import TA_CENTER, TA_LEFT
    from reportlab.platypus import (SimpleDocTemplate, Paragraph, Spacer,
                                    Table, TableStyle, HRFlowable)
    from reportlab.lib.colors import HexColor

    W, H = A4
    buf = io.BytesIO()
    doc = SimpleDocTemplate(buf, pagesize=A4,
                            leftMargin=18*mm, rightMargin=18*mm,
                            topMargin=22*mm, bottomMargin=18*mm)
    NAVY_C  = HexColor("#152743")
    TEAL_C  = HexColor("#1B9E8A")
    AMBER_C = HexColor("#E87B35")
    RED_C   = HexColor("#C0392B")
    SLATE_C = HexColor("#EEF2F7")
    WHITE_C = rl_colors.white

    base = getSampleStyleSheet()
    S = {
        'title': ParagraphStyle('t', fontName='Helvetica-Bold', fontSize=18,
                                textColor=WHITE_C, leading=22),
        'sub':   ParagraphStyle('s', fontName='Helvetica', fontSize=10,
                                textColor=HexColor("#AECDE8"), leading=14),
        'h2':    ParagraphStyle('h2', fontName='Helvetica-Bold', fontSize=12,
                                textColor=NAVY_C, spaceBefore=10, spaceAfter=4),
        'body':  ParagraphStyle('b', fontName='Helvetica', fontSize=9,
                                textColor=HexColor("#2C3A55"), leading=14),
        'note':  ParagraphStyle('n', fontName='Helvetica-Oblique', fontSize=8,
                                textColor=HexColor("#6B7A99"), leading=12),
        'thdr':  ParagraphStyle('th', fontName='Helvetica-Bold', fontSize=8,
                                textColor=WHITE_C),
        'tcell': ParagraphStyle('tc', fontName='Helvetica', fontSize=8,
                                textColor=HexColor("#2C3A55")),
        'disc':  ParagraphStyle('d', fontName='Helvetica-Oblique', fontSize=7.5,
                                textColor=HexColor("#9AA3B8"), alignment=TA_CENTER),
    }

    story = []

    # Cover band
    cover_data = [[
        Paragraph(f"Symptom & Side-Effect Report", S['title']),
        Spacer(1, 4),
        Paragraph(f"Patient: {patient_name or 'Not specified'}  ·  "
                  f"{sarcoma_type}  ·  Phase: {treatment_phase}", S['sub']),
        Paragraph(f"Generated: {datetime.now().strftime('%d %B %Y, %H:%M')}  ·  "
                  f"Entries shown: {len(entries)}", S['sub']),
    ]]
    cover_tbl = Table(cover_data, colWidths=[W - 36*mm])
    cover_tbl.setStyle(TableStyle([
        ('BACKGROUND', (0,0), (-1,-1), NAVY_C),
        ('TOPPADDING',    (0,0), (-1,-1), 14),
        ('BOTTOMPADDING', (0,0), (-1,-1), 14),
        ('LEFTPADDING',   (0,0), (-1,-1), 16),
        ('RIGHTPADDING',  (0,0), (-1,-1), 16),
    ]))
    story.append(cover_tbl)
    story.append(Spacer(1, 10))

    # Instructions for clinician
    story.append(Paragraph("For your clinician", S['h2']))
    story.append(Paragraph(
        "This report was generated by the patient using the Sarcoma Hub Symptom Tracker. "
        "Scores are self-reported on a 0–10 scale. For pain, fatigue, and nausea: "
        "0 = none, 10 = worst. For appetite, mood, sleep, and mobility: "
        "0 = worst, 10 = best. Additional symptoms are checked when present.",
        S['body']))
    story.append(HRFlowable(width="100%", thickness=1, color=TEAL_C, spaceAfter=6, spaceBefore=6))

    # Summary averages table
    if entries:
        story.append(Paragraph("Average scores across this period", S['h2']))
        avgs = {}
        for key, label, _, _ in CORE_SYMPTOMS:
            vals = [e.get(key, 0) for e in entries if e.get(key) is not None]
            if vals:
                avgs[key] = (label, round(sum(vals)/len(vals), 1))

        inv_keys = {"appetite", "mood", "sleep", "mobility"}
        hdr = [Paragraph(h, S['thdr']) for h in
               ["Symptom", "Avg (0-10)", "Trend", "Flag"]]
        rows = [hdr]
        for key, (label, avg) in avgs.items():
            invert = key in inv_keys
            flag = ""
            if invert:
                if avg < 4: flag = "⚠ Low — discuss"
            else:
                if avg > 6: flag = "⚠ High — discuss"
                elif avg > 4: flag = "Moderate"
            rows.append([
                Paragraph(label, S['tcell']),
                Paragraph(str(avg), S['tcell']),
                Paragraph("─" * int(avg), S['tcell']),
                Paragraph(flag, S['tcell']),
            ])
        col_w = [(W-36*mm)*f for f in [0.30, 0.18, 0.32, 0.20]]
        t = Table(rows, colWidths=col_w)
        t.setStyle(TableStyle([
            ('BACKGROUND', (0,0), (-1,0), NAVY_C),
            ('ROWBACKGROUNDS', (0,1), (-1,-1), [WHITE_C, SLATE_C]),
            ('GRID', (0,0), (-1,-1), 0.4, HexColor("#D0D8E8")),
            ('TOPPADDING', (0,0), (-1,-1), 4),
            ('BOTTOMPADDING', (0,0), (-1,-1), 4),
            ('LEFTPADDING', (0,0), (-1,-1), 6),
            ('RIGHTPADDING', (0,0), (-1,-1), 6),
            ('VALIGN', (0,0), (-1,-1), 'MIDDLE'),
        ]))
        story.append(t)
        story.append(Spacer(1, 8))

    # Daily log
    story.append(Paragraph("Daily log", S['h2']))
    hdr2 = [Paragraph(h, S['thdr']) for h in
            ["Date", "Pain", "Fatigue", "Nausea", "Appetite", "Mood",
             "Sleep", "Mobility", "Other symptoms / Notes"]]
    rows2 = [hdr2]
    for e in entries[-30:]:   # last 30 entries max
        other = ", ".join(e.get("additional", [])) or "—"
        notes = e.get("notes", "").strip()
        combined = other
        if notes:
            combined = f"{combined}  |  {notes}" if other != "—" else notes
        rows2.append([
            Paragraph(e.get("date", ""), S['tcell']),
            Paragraph(str(e.get("pain",    "—")), S['tcell']),
            Paragraph(str(e.get("fatigue", "—")), S['tcell']),
            Paragraph(str(e.get("nausea",  "—")), S['tcell']),
            Paragraph(str(e.get("appetite","—")), S['tcell']),
            Paragraph(str(e.get("mood",    "—")), S['tcell']),
            Paragraph(str(e.get("sleep",   "—")), S['tcell']),
            Paragraph(str(e.get("mobility","—")), S['tcell']),
            Paragraph(combined[:120], S['tcell']),
        ])
    col_w2 = [(W-36*mm)*f for f in [0.10,0.07,0.07,0.07,0.08,0.06,0.07,0.08,0.40]]
    t2 = Table(rows2, colWidths=col_w2, repeatRows=1)
    t2.setStyle(TableStyle([
        ('BACKGROUND', (0,0), (-1,0), NAVY_C),
        ('ROWBACKGROUNDS', (0,1), (-1,-1), [WHITE_C, SLATE_C]),
        ('GRID', (0,0), (-1,-1), 0.3, HexColor("#D0D8E8")),
        ('TOPPADDING', (0,0), (-1,-1), 3),
        ('BOTTOMPADDING', (0,0), (-1,-1), 3),
        ('LEFTPADDING', (0,0), (-1,-1), 4),
        ('RIGHTPADDING', (0,0), (-1,-1), 4),
        ('VALIGN', (0,0), (-1,-1), 'TOP'),
        ('FONTSIZE', (0,0), (-1,-1), 7.5),
    ]))
    story.append(t2)
    story.append(Spacer(1, 8))

    # Questions to ask
    story.append(HRFlowable(width="100%", thickness=1, color=TEAL_C, spaceBefore=4, spaceAfter=4))
    story.append(Paragraph("Suggested topics to raise with your clinician", S['h2']))
    inv_keys_set = {"appetite", "mood", "sleep", "mobility"}
    for key, (label, avg) in avgs.items():
        invert = key in inv_keys_set
        concern = (invert and avg < 4) or (not invert and avg > 6)
        if concern:
            story.append(Paragraph(
                f"• {label} (avg {avg}/10) — ask about management strategies "
                f"and whether this level warrants treatment adjustment.",
                S['body']))
    story.append(Spacer(1, 6))
    story.append(Paragraph(
        "This report was generated by the Emily Muggeridge Sarcoma Hub (sarcomahub.org) and is intended "
        "as a patient-completed symptom diary. It does not replace clinical assessment.",
        S['disc']))

    doc.build(story)
    buf.seek(0)
    return buf.read()


