def _call_claude_decoder(report_text: str) -> str:
    """Call the Anthropic API to decode a pathology report."""
    import urllib.request
    import json as _json

    system = """You are a sarcoma pathology expert helping a patient understand their pathology report.
Your role is to translate medical terminology into clear, compassionate, plain English.

For the pathology report text provided, produce a structured explanation with these sections:

## 📋 What your report says — in plain English

For each significant term or finding, provide:
- **Term** — what it means in simple language
- **Why it matters** — clinical significance
- **Question to ask your doctor** — one specific, actionable question

Group findings under these headings where relevant:
- Diagnosis & Tumour Type
- Grade & Aggressiveness  
- Surgical Margins
- Molecular & Genetic Findings
- Stage & Spread

## ⚠️ Key points to flag with your clinical team
A concise bullet list (max 5) of the most important things that need discussion.

## 💬 Questions to bring to your next appointment
A numbered list of 5–8 specific, actionable questions based on this report.

## 📌 Important note
End with a 2-sentence reminder that this explanation is for understanding only and all decisions should be made with their specialist team.

Tone: warm, clear, never alarmist. Explain as if talking to an intelligent person who has no medical background. 
Never speculate about prognosis or survival numbers. Focus on understanding, not prediction."""

    payload = {
        "model": "claude-sonnet-4-6",
        "max_tokens": 1800,
        "system": system,
        "messages": [
            {"role": "user", "content": f"Please decode this sarcoma pathology report:\n\n{report_text}"}
        ]
    }

    api_key = os.environ.get("ANTHROPIC_API_KEY", "")
    if not api_key:
        return (
            "**API key not configured.** To enable AI decoding, set the "
            "`ANTHROPIC_API_KEY` environment variable before starting Streamlit:\n\n"
            "```\nexport ANTHROPIC_API_KEY=sk-ant-...\nstreamlit run sarcoma_hub.py\n```\n\n"
            "In the meantime, use the **Quick Term Lookup** or **Full Glossary** tabs."
        )
    req = urllib.request.Request(
        "https://api.anthropic.com/v1/messages",
        data=_json.dumps(payload).encode(),
        headers={
            "content-type": "application/json",
            "anthropic-version": "2023-06-01",
            "x-api-key": api_key,
        },
        method="POST"
    )
    try:
        with urllib.request.urlopen(req, timeout=45) as resp:
            data = _json.loads(resp.read())
            for block in data.get("content", []):
                if block.get("type") == "text":
                    return block["text"]
        return "No response received."
    except Exception as e:
        return f"_API error: {e}. Please use the Quick Term Lookup tab instead._"


