        st.markdown("Type a term — or click any button below to look it up instantly.")

        # ── Single source of truth: "decoder_active" ──────────────────────────
        # Both the buttons and the text input write here.
        # Results always read from here.
        # This avoids the Streamlit bug where setting st.session_state[key]
        # before rendering st.text_input(key=key) gets silently overwritten.
        if "decoder_active" not in st.session_state:
            st.session_state["decoder_active"] = ""

        # ── Quick-pick buttons (rendered ABOVE the text box) ──────────────────
        st.markdown("**Commonly encountered terms — click to look up instantly:**")
