def _journal_pdf(journal_data: dict) -> bytes:
    """Generate a keepsake-quality PDF of the completed journal."""
    from reportlab.lib.pagesizes import A4
    from reportlab.lib.units import mm
    from reportlab.lib.styles import ParagraphStyle
    from reportlab.lib.enums import TA_CENTER, TA_LEFT, TA_JUSTIFY
    from reportlab.platypus import (
        SimpleDocTemplate, Paragraph, Spacer, PageBreak,
        HRFlowable, KeepTogether, Table, TableStyle,
    )
    from reportlab.lib.colors import HexColor, white, black
    from reportlab.pdfgen import canvas as rl_canvas

    W, H   = A4
    CREAM  = HexColor("#FDFAF5")
    GOLD_D = HexColor("#8B6914")
    GOLD_L = HexColor("#C9A84C")
    NAVY_D = HexColor("#152743")
    TEAL_D = HexColor("#1B9E8A")
    MUTED  = HexColor("#7A7060")
    RUST   = HexColor("#8B3A2A")
    buf    = io.BytesIO()

    # ── Page callbacks ─────────────────────────────────────────────────────────
    author_name = journal_data.get("cover", {}).get("name", "")
    dedication  = journal_data.get("cover", {}).get("dedication", "")

    def cover_page(canv, doc):
        canv.saveState()
        # Deep navy background
        canv.setFillColor(NAVY_D)
        canv.rect(0, 0, W, H, fill=1, stroke=0)
        # Gold border frame
        canv.setStrokeColor(GOLD_L)
        canv.setLineWidth(0.8)
        canv.rect(12*mm, 12*mm, W-24*mm, H-24*mm, fill=0, stroke=1)
        canv.setLineWidth(0.3)
        canv.rect(14*mm, 14*mm, W-28*mm, H-28*mm, fill=0, stroke=1)
        # Teal accent stripe
        canv.setFillColor(TEAL_D)
        canv.rect(0, H*0.42, W, 2.5*mm, fill=1, stroke=0)
        canv.rect(0, H*0.42 - 5*mm, W, 1*mm, fill=1, stroke=0)
        # Title
        canv.setFillColor(white)
        canv.setFont("Times-Roman", 9)
        canv.drawCentredString(W/2, H*0.72, "A  L E G A C Y  &  M E M O R Y  J O U R N A L")
        canv.setFont("Times-Italic", 36)
        canv.setFillColor(GOLD_L)
        title_text = author_name if author_name else "My Story"
        canv.drawCentredString(W/2, H*0.60, title_text)
        canv.setFillColor(white)
        canv.setFont("Times-Italic", 13)
        canv.drawCentredString(W/2, H*0.53, "In my own words")
        # Dedication
        if dedication:
            canv.setFillColor(GOLD_L)
            canv.setFont("Times-Italic", 10)
            canv.drawCentredString(W/2, H*0.35, f"\u201c{dedication}\u201d")
        # Date
        canv.setFillColor(MUTED)
        canv.setFont("Helvetica", 8)
        canv.drawCentredString(W/2, 22*mm,
            f"Created {datetime.now().strftime('%B %Y')}  \u00b7  Sarcoma Hub")
        canv.restoreState()

    def inner_page(canv, doc):
        canv.saveState()
        canv.setFillColor(CREAM)
        canv.rect(0, 0, W, H, fill=1, stroke=0)
        # Subtle top stripe
        canv.setFillColor(NAVY_D)
        canv.rect(0, H-9*mm, W, 9*mm, fill=1, stroke=0)
        canv.setFillColor(TEAL_D)
        canv.rect(0, H-10.5*mm, W, 1.5*mm, fill=1, stroke=0)
        # Header text
        canv.setFillColor(white)
        canv.setFont("Helvetica", 7.5)
        canv.drawString(18*mm, H-6*mm, "Legacy & Memory Journal")
        canv.setFont("Helvetica", 7.5)
        if author_name:
            canv.drawRightString(W-18*mm, H-6*mm, author_name)
        # Footer
        canv.setFillColor(GOLD_D)
        canv.rect(0, 0, W, 8*mm, fill=1, stroke=0)
        canv.setFillColor(white)
        canv.setFont("Helvetica", 7)
        canv.drawCentredString(W/2, 2.8*mm,
            f"Page {doc.page - 1}  \u00b7  Emily Muggeridge Sarcoma Hub  \u00b7  sarcomahub.org")
        canv.restoreState()

    # ── Styles ─────────────────────────────────────────────────────────────────
    def S(name, **kw):
        base = {
            "fontName": "Times-Roman", "fontSize": 11,
            "textColor": NAVY_D, "leading": 17,
            "spaceAfter": 6,
        }
        base.update(kw)
        return ParagraphStyle(name, **base)

    s_chapter   = S("ch", fontName="Times-Italic", fontSize=22,
                    textColor=NAVY_D, spaceBefore=8, spaceAfter=4,
                    leading=26, alignment=TA_LEFT)
    s_sub       = S("sub", fontName="Helvetica", fontSize=9.5,
                    textColor=TEAL_D, spaceAfter=12, leading=13)
    s_body      = S("body", alignment=TA_JUSTIFY, spaceAfter=9,
                    textColor=HexColor("#2A2218"), leading=18, fontSize=11)
    s_empty     = S("empty", fontName="Helvetica-Oblique", fontSize=10,
                    textColor=MUTED, alignment=TA_CENTER)
    s_disc      = S("disc", fontName="Helvetica-Oblique", fontSize=7.5,
                    textColor=MUTED, alignment=TA_CENTER, spaceAfter=0)
    s_toc_title = S("tot", fontName="Helvetica-Bold", fontSize=10,
                    textColor=NAVY_D, spaceAfter=2, leading=14)
    s_toc_entry = S("toe", fontName="Times-Roman", fontSize=10,
                    textColor=HexColor("#2A2218"), spaceAfter=4, leading=14)

    # ── Build story ────────────────────────────────────────────────────────────
    doc = SimpleDocTemplate(
        buf, pagesize=A4,
        leftMargin=22*mm, rightMargin=22*mm,
        topMargin=18*mm, bottomMargin=16*mm,
    )
    story = []

    # Cover (blank page for the cover_page callback)
    story.append(Paragraph(" ", s_empty))
    story.append(PageBreak())

    # Table of contents
    story.append(Spacer(1, 6*mm))
    story.append(Paragraph("Contents", S("toc_h", fontName="Helvetica-Bold",
                            fontSize=16, textColor=NAVY_D, spaceAfter=8)))
    story.append(HRFlowable(width="100%", thickness=0.6,
                             color=GOLD_L, spaceAfter=10))
    for sec in JOURNAL_SECTIONS:
        content = journal_data.get(sec["id"], "").strip()
        status  = "Written" if content else "Not yet written"
        col_w   = [(W-44*mm)*0.82, (W-44*mm)*0.18]
        row     = Table(
            [[Paragraph(f"{sec['emoji']}  {sec['title']}", s_toc_entry),
              Paragraph(status, S("st", fontName="Helvetica", fontSize=9,
                                  textColor=TEAL_D if content else MUTED,
                                  alignment=TA_CENTER))]],
            colWidths=col_w
        )
        row.setStyle(TableStyle([
            ("TOPPADDING",    (0,0), (-1,-1), 3),
            ("BOTTOMPADDING", (0,0), (-1,-1), 3),
            ("LINEBELOW",     (0,0), (-1,-1), 0.3, HexColor("#D8D0C0")),
            ("VALIGN",        (0,0), (-1,-1), "MIDDLE"),
        ]))
        story.append(row)
    story.append(PageBreak())

    # Sections
    for sec in JOURNAL_SECTIONS:
        content = journal_data.get(sec["id"], "").strip()
        story.append(Spacer(1, 4*mm))
        story.append(KeepTogether([
            HRFlowable(width="100%", thickness=1.2,
                       color=TEAL_D, spaceAfter=8),
            Paragraph(f"{sec['emoji']}  {sec['title']}", s_chapter),
            Paragraph(sec["subtitle"], s_sub),
        ]))

        if content:
            for para in content.split("\n\n"):
                para = para.strip()
                if para:
                    for line in para.split("\n"):
                        if line.strip():
                            story.append(Paragraph(
                                line.replace("&", "&amp;")
                                    .replace("<", "&lt;")
                                    .replace(">", "&gt;"),
                                s_body))
                    story.append(Spacer(1, 3*mm))
        else:
            story.append(Spacer(1, 6*mm))
            story.append(Paragraph("[ This section has not yet been written ]",
                                   s_empty))
            story.append(Spacer(1, 6*mm))

        story.append(PageBreak())

    # Closing page
    story.append(Spacer(1, 30*mm))
    story.append(HRFlowable(width="60%", thickness=0.6,
                             color=GOLD_L, spaceAfter=12, spaceBefore=0))
    story.append(Paragraph(
        "This journal was written with love and care.",
        S("cl", fontName="Times-Italic", fontSize=13,
          textColor=NAVY_D, alignment=TA_CENTER)))
    story.append(Spacer(1, 3*mm))
    if author_name:
        story.append(Paragraph(
            author_name,
            S("cn", fontName="Times-Italic", fontSize=16,
              textColor=GOLD_D, alignment=TA_CENTER)))
    story.append(Spacer(1, 8*mm))
    story.append(Paragraph(
        "Created using the Emily Muggeridge Sarcoma Hub  \u00b7  sarcomahub.org",
        s_disc))

    def first_page(canv, doc):
        cover_page(canv, doc)

    def later_pages(canv, doc):
        inner_page(canv, doc)

    doc.build(story, onFirstPage=first_page, onLaterPages=later_pages)
    buf.seek(0)
    return buf.read()


def tab_legacy_journal():
    """Legacy & Memory Journal — Tab 10."""

