def _build_timeline_chart(events: list) -> object:
    """Return a matplotlib figure of the treatment timeline."""
    if not events:
        return None

    from datetime import datetime as _dt
    sorted_ev = sorted(events, key=lambda e: e["date"])
    try:
        dts = [_dt.strptime(e["date"], "%Y-%m-%d") for e in sorted_ev]
    except Exception:
        return None

    # --- layout ---
    fig, ax = plt.subplots(figsize=(11, 3.8))
    fig.patch.set_facecolor("#EEF2F7")
    ax.set_facecolor("#EEF2F7")

    # ── baseline ──────────────────────────────────────────────────────────────
    ax.axhline(0, color="#9AAABB", lw=2.5, zorder=1, solid_capstyle="round")

    # ── today marker ─────────────────────────────────────────────────────────
    today = _dt.now()
    if dts[0] <= today <= dts[-1]:
        ax.axvline(today, color="#F5B800", lw=1.5, ls="--", zorder=2, alpha=0.8)
        ax.text(today, 1.62, "Today", ha="center", va="bottom",
                fontsize=7, color="#8B6914", fontweight="bold")

    # ── plot events ───────────────────────────────────────────────────────────
    used_positions = {}   # date → list of y offsets used
    for i, (ev, dt) in enumerate(zip(sorted_ev, dts)):
        col  = TL_COLORS.get(ev["type"], "#666")
        # alternate above / below; stack if same date
        sign = 1 if i % 2 == 0 else -1
        base = sign * 0.55
        # nudge if date already occupied
        key  = dt.date()
        occupied = used_positions.get(key, [])
        while any(abs(base - y) < 0.28 for y in occupied):
            base += sign * 0.3
        occupied.append(base)
        used_positions[key] = occupied

        # stem
        ax.plot([dt, dt], [0, base * 0.85], color=col, lw=1.4, zorder=2)
        # marker
        marker = "D" if ev["type"] == "Milestone" else                  "s" if "scan" in ev["type"].lower() or "MRI" in ev["type"] or "X-ray" in ev["type"] else                  "^" if ev["type"] == "Surgery" else "o"
        ax.scatter([dt], [base], color=col, s=72, zorder=4,
                   marker=marker, edgecolors="white", linewidths=0.6)

        # label
        label = ev["title"][:22] + ("…" if len(ev["title"]) > 22 else "")
        va    = "bottom" if base > 0 else "top"
        yoff  = base + (0.1 if base > 0 else -0.1)
        ax.text(dt, yoff, label, ha="center", va=va, fontsize=6.8,
                color=col, fontweight="bold", wrap=False,
                bbox=dict(boxstyle="round,pad=0.1", fc="#EEF2F7",
                          ec="none", alpha=0.75))

    # ── axes ──────────────────────────────────────────────────────────────────
    span = (dts[-1] - dts[0]).days
    if span < 90:
        loc = mdates.WeekdayLocator(byweekday=0)
        fmt = mdates.DateFormatter("%d %b")
    elif span < 400:
        loc = mdates.MonthLocator()
        fmt = mdates.DateFormatter("%b %Y")
    else:
        loc = mdates.MonthLocator(interval=2)
        fmt = mdates.DateFormatter("%b '%y")

    ax.xaxis.set_major_locator(loc)
    ax.xaxis.set_major_formatter(fmt)
    plt.setp(ax.xaxis.get_majorticklabels(),
             rotation=35, ha="right", fontsize=8, color="#2C3A55")
    ax.set_ylim(-2.0, 2.1)
    ax.set_yticks([])
    for spine in ["top", "right", "left"]:
        ax.spines[spine].set_visible(False)
    ax.spines["bottom"].set_color("#9AAABB")

    # ── legend ────────────────────────────────────────────────────────────────
    seen_types = list(dict.fromkeys(e["type"] for e in sorted_ev))
    handles = [
        Line2D([0], [0], marker="o", color="w",
               markerfacecolor=TL_COLORS.get(t, "#666"),
               markersize=7, label=t)
        for t in seen_types[:8]
    ]
    ax.legend(handles=handles, fontsize=6.5, ncol=min(4, len(handles)),
              loc="upper left", framealpha=0.6, facecolor="#EEF2F7",
              edgecolor="#C5CFDC", handletextpad=0.4, columnspacing=0.8)

    fig.tight_layout(pad=0.6)
    return fig


