def _build_ctgov_url(condition: str, phase: str = "",
                     country: str = "") -> str:
    """Build a ClinicalTrials.gov search URL for a given condition."""
    import urllib.parse
    params = {
        "cond": condition,
        "recrs": "a",      # recruiting
    }
    if phase:
        params["phase"] = phase
    if country:
        params["locStr"] = country
        params["distance"] = "500"
    return "https://clinicaltrials.gov/search?" + urllib.parse.urlencode(params)


def _generate_trial_profile(profile: dict) -> str:
    """Call Claude to generate a personalised trial eligibility summary."""
    import urllib.request, json as _json, os as _os

    api_key = _os.environ.get("ANTHROPIC_API_KEY", "")
    if not api_key:
        return (
            "**API key not set.** Set `ANTHROPIC_API_KEY` before running Streamlit "
            "to enable AI analysis.\\n\\nYour trial profile has still been saved — "
            "use the Search Links below to search ClinicalTrials.gov directly."
        )

    sarc_type    = profile.get("sarcoma_type", "unknown sarcoma")
    grade        = profile.get("grade", "unknown grade")
    stage        = profile.get("stage", "unknown stage")
    molecular    = profile.get("molecular", [])
    prior_tx     = profile.get("prior_tx", [])
    n_lines      = profile.get("n_lines", "unknown")
    ecog         = profile.get("ecog", "unknown")
    organ        = profile.get("organ_concerns", [])
    goals        = profile.get("goals", [])
    travel       = profile.get("travel", "unknown")
    phase_pref   = profile.get("phase_pref", "any")
    country      = profile.get("country", "")
    extra        = profile.get("extra", "")
    measurable   = profile.get("measurable", "unknown")

    mol_str  = ", ".join(molecular) if molecular else "none confirmed / not tested"
    tx_str   = ", ".join(prior_tx)  if prior_tx  else "none"
    org_str  = ", ".join(organ)     if organ     else "none"
    goal_str = ", ".join(goals)     if goals     else "not specified"

    system = """You are a specialist sarcoma oncology nurse and clinical trial coordinator 
helping a patient understand their clinical trial options.

Given the patient's profile, produce a structured, personalised trial eligibility analysis.

Format your response with these exact sections using Markdown:

## 🎯 Your Trial Profile Summary
2–3 sentences summarising who this patient is from a trial eligibility perspective — 
their disease, treatment history, molecular landscape, and what kinds of trials they would fit.

## ✅ Trial Types Most Likely to Match You
A bullet list of 4–8 specific trial types, drugs, or targets that are relevant to THIS patient.
For each, one sentence explaining why it's relevant to their profile.
Be specific — name real drug classes, gene targets, biomarkers, trial types.

## 🔑 Key Eligibility Factors for You
What this patient should specifically check when reviewing any trial's eligibility criteria.
Mention any factors that might exclude them (ECOG, organ function, prior treatments) 
and any factors that might make them especially eligible (molecular markers, rare subtype).

## 🔍 How to Search Effectively
3–4 specific ClinicalTrials.gov search strategies for THIS patient — 
exact terms to type, filters to set, what to look for in the results.

## 🏥 Specialist Centres to Contact
3–5 specific high-volume sarcoma centres with particularly strong trial portfolios 
relevant to this patient's subtype. Real named centres.

## 💬 Questions to Ask
5–7 specific questions this patient should ask when enquiring about a specific trial,
tailored to their situation.

## ⚠️ Important Reminders
2–3 brief reminders about trial participation that are especially relevant to their situation.

Tone: warm, expert, empowering. Be specific and actionable — not generic.
Never suggest the patient won't qualify without specific reason.
"""

    user_msg = f"""Patient profile:
- Sarcoma type: {sarc_type} — {grade} grade, {stage}
- Molecular markers: {mol_str}
- Prior systemic treatments: {tx_str}
- Number of prior lines: {n_lines}
- ECOG performance status: {ecog}
- Organ concerns: {org_str}
- Measurable disease on imaging: {measurable}
- Treatment goal: {goal_str}
- Willing to travel: {travel}
- Phase preference: {phase_pref}
- Country/region: {country or "not specified"}
- Additional context: {extra or "none"}

Please generate a personalised clinical trial eligibility analysis for this patient."""

    payload = {
        "model": "claude-sonnet-4-6",
        "max_tokens": 1800,
        "system": system,
        "messages": [{"role": "user", "content": user_msg}]
    }
    req = urllib.request.Request(
        "https://api.anthropic.com/v1/messages",
        data=_json.dumps(payload).encode(),
        headers={
            "content-type": "application/json",
            "anthropic-version": "2023-06-01",
            "x-api-key": api_key,
        },
        method="POST"
    )
    try:
        with urllib.request.urlopen(req, timeout=45) as resp:
            data = _json.loads(resp.read())
            for block in data.get("content", []):
                if block.get("type") == "text":
                    return block["text"]
        return "_No response received._"
    except Exception as e:
        return f"_API error: {e}._"


def _build_search_links(profile: dict) -> list:
    """Generate a set of targeted ClinicalTrials.gov search links."""
    sarc_type = profile.get("sarcoma_type", "sarcoma")
    molecular = profile.get("molecular", [])
    country   = profile.get("country", "")
    links     = []

    # 1. Subtype-specific recruiting
    type_clean = sarc_type.replace(" / ", " ").replace("/", " ")
    links.append({
        "label":  f"{sarc_type} — all recruiting trials",
        "url":    _build_ctgov_url(type_clean, country=country),
        "note":   "Broadest search — all recruiting trials for your subtype.",
        "icon":   "🔍",
    })

    # 2. General sarcoma if subtype is unusual
    links.append({
        "label":  "Soft tissue sarcoma — all phases, recruiting",
        "url":    _build_ctgov_url("soft tissue sarcoma", country=country),
        "note":   "Useful for basket trials that include multiple STS subtypes.",
        "icon":   "🧪",
    })

    # 3. Molecular-specific
    mol_map = {
        "NTRK1/2/3 gene fusion":         ("NTRK fusion sarcoma",    "NTRK inhibitor larotrectinib entrectinib"),
        "MDM2 amplification":             ("liposarcoma MDM2",        "MDM2 inhibitor liposarcoma"),
        "CDK4 amplification":             ("liposarcoma CDK4",        "CDK4 inhibitor liposarcoma"),
        "PDGFRA D842V specifically":      ("GIST PDGFRA D842V",       "avapritinib GIST PDGFRA"),
        "KIT mutation (exon 11)":         ("GIST KIT exon 11",        "imatinib resistance GIST"),
        "INI1 / SMARCB1 loss (epithelioid sarcoma)": ("epithelioid sarcoma",  "tazemetostat EZH2 epithelioid"),
        "SS18-SSX1 / SS18-SSX2 fusion (synovial sarcoma)": ("synovial sarcoma",    "synovial sarcoma targeted therapy"),
        "EWSR1-FLI1 or EWSR1-ERG fusion (Ewing sarcoma)": ("Ewing sarcoma",       "Ewing sarcoma targeted"),
        "IDH1 mutation":                  ("chondrosarcoma IDH1",     "IDH inhibitor chondrosarcoma"),
        "IDH2 mutation":                  ("chondrosarcoma IDH2",     "IDH inhibitor chondrosarcoma"),
        "NF1 loss / NF1 syndrome":        ("MPNST NF1",               "MPNST MEK inhibitor"),
        "High tumour mutation burden (TMB-H)": ("sarcoma TMB",        "immunotherapy sarcoma high TMB"),
        "MSI-H / mismatch repair deficient": ("sarcoma MSI-H",       "pembrolizumab MSI sarcoma"),
    }
    added_mol = set()
    for mol in molecular:
        if mol in mol_map and mol not in added_mol:
            search_condition, note_query = mol_map[mol]
            links.append({
                "label":  f"Trials targeting your marker: {mol[:45]}",
                "url":    _build_ctgov_url(search_condition, country=country),
                "note":   f"Filter for: {note_query}",
                "icon":   "🧬",
            })
            added_mol.add(mol)

    # 4. Phase-specific
    links.append({
        "label":  f"{sarc_type} — Phase II trials only",
        "url":    _build_ctgov_url(type_clean, phase="2", country=country),
        "note":   "Phase II has preliminary efficacy data — more evidence than Phase I.",
        "icon":   "II",
    })

    # 5. SARC consortium
    links.append({
        "label":  "SARC open trials (all sarcoma types)",
        "url":    "https://sarctrials.org/category/clinical-trials/",
        "note":   "The SARC consortium runs many landmark sarcoma trials. Check for your subtype.",
        "icon":   "🏛",
    })

    # 6. EU Clinical Trials Register
    links.append({
        "label":  "EU Clinical Trials Register — sarcoma",
        "url":    f"https://www.clinicaltrialsregister.eu/ctr-search/search?query={type_clean.replace(' ', '+')}&status=ongoing",
        "note":   "Covers European trials not always listed on ClinicalTrials.gov.",
        "icon":   "🇪🇺",
    })

    # 7. SFA clinical trial matching (personalised)
    links.append({
        "label":  "SFA personalised trial matching (free service)",
        "url":    "https://curesarcoma.org/support-resources/sarcoma-clinical-trials/",
        "note":   "The Sarcoma Foundation of America offers free personalised trial matching.",
        "icon":   "🎗",
    })

    return links


def tab_trial_screener():
    """Clinical Trial Eligibility Screener — Tab 15."""

    if "screener_profile" not in st.session_state:
        st.session_state["screener_profile"] = {}
    if "screener_result"  not in st.session_state:
        st.session_state["screener_result"]  = None
    if "screener_step"    not in st.session_state:
        st.session_state["screener_step"]    = 0

    profile = st.session_state["screener_profile"]
    step    = st.session_state["screener_step"]

    # ── CSS ───────────────────────────────────────────────────────────────────
    st.html(f"""
<style>
.sc-hero {{
    background:linear-gradient(135deg,#1A1A5C 0%,#152743 100%);
    border-radius:16px; padding:2.5rem; margin-bottom:1.4rem;
    color:white; position:relative; overflow:hidden;
}}
.sc-hero::before {{
    content:''; position:absolute; top:-50px; right:-60px;
    width:250px; height:250px;
    background:radial-gradient(circle,rgba(27,158,138,.2) 0%,transparent 70%);
    border-radius:50%;
}}
.sc-hero h1 {{
    font-family:'DM Serif Display',serif; font-size:2.2rem;
    color:{TEAL2}; margin:0 0 .5rem; font-weight:400;
}}
.sc-hero p {{
    opacity:.85; font-size:.97rem; line-height:1.6;
    max-width:560px; margin:0; font-weight:300;
}}
.step-bar {{
    display:flex; gap:.4rem; margin-bottom:1.4rem;
}}
.step-pill {{
    flex:1; height:6px; border-radius:3px;
    background:#DDE5EF; transition:background .3s;
}}
.step-pill.done {{ background:{TEAL}; }}
.step-pill.active {{ background:{GOLD}; }}
.step-label {{
    font-size:.72rem; color:{MUTED}; font-weight:600;
    text-align:center; margin-top:.25rem;
    text-transform:uppercase; letter-spacing:.04em;
}}
.sc-section {{
    background:{WHITE}; border:1px solid #DDE5EF;
    border-radius:12px; padding:1.3rem 1.5rem;
    margin-bottom:1rem;
}}
.sc-section h3 {{
    font-family:'DM Serif Display',serif; font-size:1.1rem;
    color:{NAVY}; margin:0 0 .8rem; font-weight:400;
    border-left:4px solid {TEAL}; padding-left:.7rem;
}}
.link-card {{
    background:{WHITE}; border:1px solid #DDE5EF;
    border-left:5px solid {TEAL}; border-radius:9px;
    padding:.85rem 1.1rem; margin-bottom:.55rem;
}}
.link-card-label {{
    font-size:.9rem; font-weight:700; color:{NAVY}; margin-bottom:.2rem;
}}
.link-card-note {{
    font-size:.78rem; color:{MUTED}; margin-bottom:.35rem; line-height:1.5;
}}
.ai-badge {{
    display:inline-block; background:#E8F0FE; color:#1A3C8A;
    border-radius:12px; padding:.2rem .7rem; font-size:.72rem;
    font-weight:700; margin-bottom:.8rem;
}}
.profile-chip {{
    display:inline-block; background:{SLATE}; border:1px solid #CDD4E2;
    border-radius:14px; padding:.18rem .65rem; font-size:.75rem;
    color:{NAVY}; margin:.15rem .15rem 0 0; font-weight:500;
}}
.ecog-box {{
    background:{SLATE}; border-radius:8px; border-left:3px solid {TEAL};
    padding:.6rem .9rem; font-size:.82rem; color:{NAVY2};
    line-height:1.5; margin-top:.4rem;
}}
</style>
""")

    # ── Hero ──────────────────────────────────────────────────────────────────
    st.html("""<div class="sc-hero">
    <h1>🔬 Clinical Trial Eligibility Screener</h1>
    <p>Answer a few questions about your diagnosis and treatment history.
       We'll build your trial profile, identify the types of trials most
       likely to match you, and give you targeted search strategies.</p>
</div>""")

    st.info(
        "⚕️ This screener gives guidance only — it cannot confirm eligibility for "
        "any specific trial. Eligibility is always assessed by the trial team. "
        "Always discuss trial options with your oncologist.",
        icon=None
    )

    # ── Progress bar ──────────────────────────────────────────────────────────
    bar_html = "".join(
        f'<div class="step-pill {"done" if i < step else "active" if i == step else ""}"></div>'
        for i in range(len(SCREENER_STEPS))
    )
    labels_html = "".join(
        f'<div class="step-label" style="flex:1;color:{"' + TEAL + '" if i < step else "' + GOLD + '" if i == step else "' + MUTED + '"}">'
        f'{SCREENER_STEPS[i]}</div>'
        for i in range(len(SCREENER_STEPS))
    )
    st.html(f'<div class="step-bar">{bar_html}</div>'
            f'<div class="step-bar" style="height:auto;margin-bottom:.6rem">'
            f'{labels_html}</div>')

    # ════════════════════════════════════════════════════════════════════════
    # STEP 0 — Diagnosis
    # ════════════════════════════════════════════════════════════════════════
    if step == 0:
        st.html('<div class="sc-section"><h3>About your diagnosis</h3></div>')

        c1, c2 = st.columns(2)
        with c1:
            sc_type = st.selectbox(
                "Sarcoma type *",
                ["Not yet confirmed"] + ALL_TYPES[1:],
                index=([
                    "Not yet confirmed"] + ALL_TYPES[1:]).index(
                    profile.get("sarcoma_type", "Not yet confirmed")
                ) if profile.get("sarcoma_type") in (["Not yet confirmed"] + ALL_TYPES[1:]) else 0,
                key="sc_type"
            )
            sc_grade = st.selectbox(
                "Grade",
                ["Not known", "Grade 1 (low)", "Grade 2 (intermediate)",
                 "Grade 3 (high)"],
                key="sc_grade"
            )
        with c2:
            sc_stage = st.selectbox(
                "Current disease status",
                ["Not yet staged",
                 "Stage I — localised, low risk",
                 "Stage II — localised, higher risk",
                 "Stage III — locally advanced / node involvement",
                 "Stage IV / metastatic",
                 "Recurrent — returned after treatment",
                 "Refractory — not responding to current treatment"],
                key="sc_stage"
            )
            sc_measurable = st.selectbox(
                "Measurable disease on recent imaging?",
                ["Yes — measurable lesion(s) visible",
                 "No — no measurable disease currently",
                 "Post-surgery — no residual disease",
                 "Not sure / not yet imaged"],
                key="sc_measurable"
            )

        sc_molecular = st.multiselect(
            "Known molecular markers (select all that apply)",
            MOLECULAR_KNOWN,
            default=profile.get("molecular", []),
            key="sc_molecular",
            help="If molecular testing has been done, select any relevant findings."
        )

        st.markdown("")
        if st.button("Next: Treatment history →", use_container_width=True,
                     type="primary", key="step0_next"):
            profile.update({
                "sarcoma_type":  sc_type,
                "grade":         sc_grade,
                "stage":         sc_stage,
                "measurable":    sc_measurable,
                "molecular":     sc_molecular,
            })
            st.session_state["screener_profile"] = profile
            st.session_state["screener_step"]    = 1
            st.rerun()

    # ════════════════════════════════════════════════════════════════════════
    # STEP 1 — Treatment history
    # ════════════════════════════════════════════════════════════════════════
    elif step == 1:
        st.html('<div class="sc-section"><h3>Your treatment history</h3></div>')

        sc_prior_tx = st.multiselect(
            "Prior systemic treatments received (select all) *",
            PRIOR_TX,
            default=profile.get("prior_tx", []),
            key="sc_prior_tx"
        )
        c1, c2 = st.columns(2)
        with c1:
            sc_lines = st.selectbox(
                "Number of prior lines of systemic therapy",
                ["None — treatment naive",
                 "1 prior line",
                 "2 prior lines",
                 "3 prior lines",
                 "4 or more prior lines"],
                key="sc_lines"
            )
            sc_surgery = st.selectbox(
                "Prior surgery for this sarcoma",
                ["Yes — complete resection (clear margins)",
                 "Yes — incomplete resection (positive margins)",
                 "Yes — debulking only",
                 "No surgery yet",
                 "Not applicable"],
                key="sc_surgery"
            )
        with c2:
            sc_radiation = st.selectbox(
                "Prior radiation therapy",
                ["No prior radiation",
                 "Yes — to primary site",
                 "Yes — to metastatic site(s)",
                 "Yes — both primary and metastatic",
                 "Radiation planned but not yet given"],
                key="sc_radiation"
            )
            sc_last_tx = st.selectbox(
                "Time since last systemic treatment",
                ["Currently on treatment",
                 "Less than 4 weeks ago",
                 "4–8 weeks ago",
                 "More than 8 weeks ago",
                 "More than 6 months ago",
                 "Never received systemic treatment"],
                key="sc_last_tx"
            )

        c_back, c_next = st.columns(2)
        with c_back:
            if st.button("← Back", use_container_width=True, key="step1_back"):
                st.session_state["screener_step"] = 0
                st.rerun()
        with c_next:
            if st.button("Next: Current health →", use_container_width=True,
                         type="primary", key="step1_next"):
                profile.update({
                    "prior_tx":   sc_prior_tx,
                    "n_lines":    sc_lines,
                    "surgery":    sc_surgery,
                    "radiation":  sc_radiation,
                    "last_tx":    sc_last_tx,
                })
                st.session_state["screener_profile"] = profile
                st.session_state["screener_step"]    = 2
                st.rerun()

    # ════════════════════════════════════════════════════════════════════════
    # STEP 2 — Current health
    # ════════════════════════════════════════════════════════════════════════
    elif step == 2:
        st.html('<div class="sc-section"><h3>Your current health</h3></div>')

        st.markdown("**ECOG Performance Status** — How would you describe your daily functioning?")
        sc_ecog = st.radio(
            "ECOG",
            ECOG_OPTIONS,
            index=ECOG_OPTIONS.index(profile.get("ecog", ECOG_OPTIONS[0])),
            key="sc_ecog",
            label_visibility="collapsed"
        )
        # Show description
        ecog_descs = {
            "0 — Fully active, no restrictions":
                "✅ ECOG 0 — Most trials are open to you. This is the most eligible performance status.",
            "1 — Light work only; not strenuous activity":
                "✅ ECOG 1 — Most trials are still open. The majority of sarcoma trials accept ECOG 0–1.",
            "2 — Self-care OK; cannot work; up >50% of day":
                "⚠️ ECOG 2 — Some trials require ECOG 0–1. You may still qualify for Phase I trials or those with broader criteria.",
            "3 — Limited self-care; in bed/chair >50% of day":
                "⚠️ ECOG 3 — Most standard trials require ECOG ≤2. Discuss with your team which options remain open.",
            "4 — Completely disabled; total bed/chair rest":
                "⚠️ ECOG 4 — Most clinical trials require ECOG ≤2. Palliative / supportive care trials may still be relevant.",
            "Not sure / prefer not to say":
                "ℹ️ Your oncologist will assess your performance status at any trial screening appointment.",
        }
        st.html(f'<div class="ecog-box">{ecog_descs.get(sc_ecog, "")}</div>')
        st.markdown("")

        sc_organ = st.multiselect(
            "Any organ function concerns? (select all that apply)",
            ORGAN_CONCERNS,
            default=profile.get("organ_concerns", ["None — all organ function normal"]),
            key="sc_organ"
        )

        c1, c2 = st.columns(2)
        with c1:
            sc_age = st.selectbox(
                "Age group",
                ["Under 18", "18–25", "26–40", "41–55",
                 "56–70", "Over 70", "Prefer not to say"],
                key="sc_age"
            )
        with c2:
            sc_country = st.text_input(
                "Country / region",
                value=profile.get("country", ""),
                placeholder="e.g. United States, United Kingdom, Germany…",
                key="sc_country"
            )

        c_back, c_next = st.columns(2)
        with c_back:
            if st.button("← Back", use_container_width=True, key="step2_back"):
                st.session_state["screener_step"] = 1
                st.rerun()
        with c_next:
            if st.button("Next: Preferences →", use_container_width=True,
                         type="primary", key="step2_next"):
                profile.update({
                    "ecog":           sc_ecog,
                    "organ_concerns": sc_organ,
                    "age":            sc_age,
                    "country":        sc_country,
                })
                st.session_state["screener_profile"] = profile
                st.session_state["screener_step"]    = 3
                st.rerun()

    # ════════════════════════════════════════════════════════════════════════
    # STEP 3 — Preferences
    # ════════════════════════════════════════════════════════════════════════
    elif step == 3:
        st.html('<div class="sc-section"><h3>Your preferences and priorities</h3></div>')

        sc_goals = st.multiselect(
            "What matters most to you right now? (select all that apply)",
            GOALS,
            default=profile.get("goals", []),
            key="sc_goals"
        )
        c1, c2 = st.columns(2)
        with c1:
            sc_travel = st.selectbox(
                "Willing to travel for a trial?",
                TRAVEL_OPTIONS,
                key="sc_travel"
            )
        with c2:
            sc_phase = st.selectbox(
                "Phase preference",
                PHASE_PREFS,
                key="sc_phase_pref"
            )

        sc_extra = st.text_area(
            "Anything else you want the screener to consider (optional)",
            value=profile.get("extra", ""),
            height=85, key="sc_extra",
            placeholder=(
                "e.g. I have a PDGFRA D842V mutation and have already had avapritinib, "
                "or I am pregnant / trying to conceive, "
                "or I'd prefer an oral drug to avoid infusions…"
            )
        )

        c_back, c_next = st.columns(2)
        with c_back:
            if st.button("← Back", use_container_width=True, key="step3_back"):
                st.session_state["screener_step"] = 2
                st.rerun()
        with c_next:
            if st.button("✨ Generate my trial profile →",
                         use_container_width=True,
                         type="primary", key="step3_next"):
                profile.update({
                    "goals":       sc_goals,
                    "travel":      sc_travel,
                    "phase_pref":  sc_phase,
                    "extra":       sc_extra,
                })
                st.session_state["screener_profile"] = profile
                with st.spinner("Analysing your profile and generating trial recommendations…"):
                    result = _generate_trial_profile(profile)
                    st.session_state["screener_result"] = result
                save_json("trial_profile.json", profile)
                st.session_state["screener_step"] = 4
                st.rerun()

    # ════════════════════════════════════════════════════════════════════════
    # STEP 4 — Results
    # ════════════════════════════════════════════════════════════════════════
    elif step == 4:
        profile = st.session_state["screener_profile"]
        result  = st.session_state.get("screener_result", "")

        # ── Profile summary chips ─────────────────────────────────────────
        chips = [
            profile.get("sarcoma_type", ""),
            profile.get("grade", ""),
            profile.get("stage", ""),
            profile.get("ecog", ""),
            profile.get("country", ""),
        ]
        chips_html = "".join(
            f'<span class="profile-chip">{c}</span>'
            for c in chips if c and c not in ("Not yet confirmed",
                                              "Not yet staged", "")
        )
        mol = profile.get("molecular", [])
        for m in mol[:4]:
            chips_html += f'<span class="profile-chip" style="background:#E0F5F2;color:{TEAL}">{m[:35]}</span>'
        st.html(f'<div style="margin-bottom:.9rem">{chips_html}</div>')

        # ── Two-column layout: AI analysis left, search links right ───────
        res_col, link_col = st.columns([3, 2], gap="large")

        with res_col:
            if result:
                st.html('<span class="ai-badge">✨ AI-generated trial profile</span>')
                st.markdown(result)

                dl_text = (
                    f"CLINICAL TRIAL PROFILE\n"
                    f"Generated: {datetime.now().strftime('%d %B %Y')}\n"
                    f"{'=' * 50}\n\n"
                    f"Sarcoma type: {profile.get('sarcoma_type','')}\n"
                    f"Grade / Stage: {profile.get('grade','')} / {profile.get('stage','')}\n"
                    f"Molecular: {', '.join(profile.get('molecular', []))}\n"
                    f"Prior treatments: {', '.join(profile.get('prior_tx', []))}\n"
                    f"ECOG: {profile.get('ecog','')}\n"
                    f"Country: {profile.get('country','')}\n\n"
                    f"{'=' * 50}\n\n"
                    + result
                )
                st.download_button(
                    "⬇️ Download full trial profile",
                    data=dl_text,
                    file_name=f"Trial_Profile_{datetime.now().strftime('%Y%m%d')}.txt",
                    mime="text/plain",
                    use_container_width=True,
                    key="dl_profile"
                )

        with link_col:
            st.markdown(f'<div class="sh">🔗 Your Search Links</div>',
                        unsafe_allow_html=True)
            st.markdown(
                "These links are pre-filtered for your profile. "
                "Open each in a new tab to see currently recruiting trials."
            )
            links = _build_search_links(profile)
            for lnk in links:
                icon = lnk.get("icon", "🔍")
                st.html(f"""
<div class="link-card">
    <div class="link-card-label">{icon} {lnk["label"]}</div>
    <div class="link-card-note">{lnk["note"]}</div>
</div>""")
                st.link_button(
                    "Open →",
                    url=lnk["url"],
                    use_container_width=True,
                )

            st.divider()
            st.markdown(f'<div class="sh">📋 How to Use These Results</div>',
                        unsafe_allow_html=True)
            st.markdown("""
**1.** Open the search links above and review recruiting trials.

**2.** Read each trial's **eligibility criteria** carefully — particularly inclusion/exclusion criteria for prior treatments, organ function, and performance status.

**3.** Note the **trial NCT number** (e.g. NCT04849676) and contact the trial site directly.

**4.** Bring your AI-generated profile and the NCT number to your next oncology appointment.

**5.** Ask your oncologist: *"Could I be screened for trial NCT_____?"*

**6.** Contact the **Sarcoma Foundation of America** (curesarcoma.org) or **SARC** (sarctrials.org) for free personalised trial matching.
""")

        st.divider()
        c_restart, c_edit = st.columns(2)
        with c_restart:
            if st.button("🔄 Start new screener", use_container_width=True,
                         key="restart_btn"):
                st.session_state["screener_step"]    = 0
                st.session_state["screener_profile"] = {}
                st.session_state["screener_result"]  = None
                st.rerun()
        with c_edit:
            if st.button("✏️ Edit my answers", use_container_width=True,
                         key="edit_btn"):
                st.session_state["screener_step"] = 0
                st.rerun()



