def main():
    inject_css()

    # Load shared data
    links     = load_json("links.json",     DEFAULT_LINKS)
    stories   = load_json("stories.json",   [])
    resources = load_json("resources.json", [])
    forum     = load_json("forum.json",     [])

    # ── Sidebar navigation ─────────────────────────────────────────────────
    if "page" not in st.session_state:
        st.session_state["page"] = "home"

    with st.sidebar:
        # Brand
        st.markdown("""
<div class="sidebar-brand">
    <h2>🎗️ The Emily Muggeridge<br>Sarcoma Hub</h2>
    <p>Patient &amp; Survivor Community</p>
</div>""", unsafe_allow_html=True)

        # Navigation groups
        for group_label, items in NAV_GROUPS:
            if group_label:
                st.markdown(
                    f'<span class="nav-group-label">{group_label}</span>',
                    unsafe_allow_html=True
                )
            for emoji, label, key in items:
                active = st.session_state["page"] == key
                btn_type = "primary" if active else "secondary"
                if st.button(
                    f"{emoji}  {label}",
                    key=f"nav_{key}",
                    use_container_width=True,
                    type=btn_type,
                ):
                    st.session_state["page"] = key
                    st.rerun()
            if group_label:
                st.markdown(
                    '<hr class="nav-divider">',
                    unsafe_allow_html=True
                )

        st.markdown("")
        st.markdown(
            '<p style="font-size:.65rem;color:rgba(255,255,255,.3);'
            'text-align:center;padding:.5rem">'
            'In memory of Emily Muggeridge  ·  sarcomahub.org<br>Feedback &amp; bugs: <a href="mailto:holdawaykeith94@gmail.com" style="color:rgba(255,255,255,.45);text-decoration:none">holdawaykeith94@gmail.com</a></p>',
            unsafe_allow_html=True
        )

    # ── Page routing ───────────────────────────────────────────────────────
    page = st.session_state["page"]

    if   page == "home":         tab_home(links, stories, resources, forum)
    elif page == "my_story":     tab_my_story()
    elif page == "symptoms":     tab_symptom_tracker()
    elif page == "timeline":     tab_treatment_timeline()
    elif page == "journal":      tab_legacy_journal()
    elif page == "pathology":    tab_pathology_decoder()
    elif page == "drugs":        tab_drug_centre()
    elif page == "trials":       tab_trial_screener()
    elif page == "appointments": tab_appt_prep()
    elif page == "links":        links = tab_links(links)
    elif page == "financial":    tab_financial_aid()
    elif page == "resources":    resources = tab_resources(resources)
    elif page == "stories":      stories = tab_patient_stories(stories)
    elif page == "forum":        forum = tab_forum(forum)
    elif page == "navigator":    tab_navigator()


if __name__ == "__main__":
    main()
